using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace ApiMcpServer;

/// <summary>
/// MCP tools that wrap a REST API via HttpClient.
/// Non-static class — services are injected via constructor.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Fetch a single resource by its unique identifier.")]
    public async Task<string> GetResource(
        [Description("The unique identifier of the resource to retrieve")] string id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching resource {Id}", id);
        var response = await httpClient.GetAsync($"/api/resources/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("List resources with optional filtering by category.")]
    public async Task<string> ListResources(
        [Description("Filter by category name (optional)")] string? category = null,
        [Description("Maximum number of results to return (1-100)")] int limit = 20,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Listing resources: category={Category}, limit={Limit}", category, limit);

        var query = $"/api/resources?limit={limit}";
        if (!string.IsNullOrEmpty(category))
            query += $"&category={Uri.EscapeDataString(category)}";

        var response = await httpClient.GetAsync(query, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool(ReadOnly = false), Description("Create a new resource with a name and optional description.")]
    public async Task<string> CreateResource(
        [Description("Name for the new resource")] string name,
        [Description("Optional description of the resource")] string? description = null,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating resource: {Name}", name);

        var payload = JsonSerializer.Serialize(new { name, description }, JsonOptions);
        var content = new StringContent(payload, System.Text.Encoding.UTF8, "application/json");

        var response = await httpClient.PostAsync("/api/resources", content, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

